import './Stepper.scss';

import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import type { FC } from 'react';
import React, { useEffect, useRef, useState } from 'react';

import { classNames } from '../../helpers/classnames';
import { Button } from '../Button';
import { Icon } from '../Icon';
import type { StepType } from './common/step.types';
import type { StepperProps } from './Stepper.types';
import { StepperMobileStep } from './StepperMobileStep';
import { StepperStep } from './StepperStep';

export const Stepper: FC<StepperProps> = ({
	switchLength = 2,
	steps,
	direction = 'vertical',
	mobile = false,
	onStepChange,
	activeStepId,
	className,
	enableAutoScroll = true,
	...props
}) => {
	const [counter, setCounter] = useState(0);
	const [showRightButton, setShowRightButton] = useState<boolean>(!mobile);
	const [showLeftButton, setShowLeftButton] = useState<boolean>(!mobile);
	const initialRenderRef = useRef(true);

	const bodyRef = useRef<HTMLDivElement>(null);

	/**
	 * Показывает или скрывает кнопки навигации
	 */
	const buttonVisibilityController = (): void => {
		const bodyElem = bodyRef?.current;

		if (!bodyElem) {
			return void 0;
		}

		const scrollIsVisible = bodyElem.scrollWidth !== bodyElem.clientWidth;
		const scrollOnStart: boolean = bodyElem.scrollLeft === 0;
		const scrollOnEnd: boolean = bodyElem.scrollLeft + bodyElem.clientWidth >= bodyElem.scrollWidth;

		setShowRightButton(!scrollOnEnd && scrollIsVisible);
		setShowLeftButton(!scrollOnStart && scrollIsVisible);
	};

	/**
	 * Показывает или скрывает кнопки навигации
	 */
	useEffect(() => {
		const bodyElem = bodyRef?.current;
		if (mobile || direction === 'vertical' || !bodyElem) {
			setShowRightButton(false);
			setShowLeftButton(false);

			return void 0;
		}

		buttonVisibilityController();

		let timeoutId: ReturnType<typeof setTimeout> | undefined;

		const scrollResizeListener = (): void => {
			timeoutId && clearTimeout(timeoutId);
			timeoutId = setTimeout(() => buttonVisibilityController(), 100);
		};

		bodyElem.addEventListener('scroll', scrollResizeListener);
		window.addEventListener('resize', scrollResizeListener);

		return () => {
			bodyElem.removeEventListener('scroll', buttonVisibilityController);
			window.removeEventListener('resize', buttonVisibilityController);
		};
	}, [direction, mobile]);

	/**
	 * Устанавливает скролл до активного элемента при рендере.
	 * Первый раз скролл происходит всегда, последующие - только если enableAutoScroll=true,
	 * а это дефолтное состояние, так как все к нему привыкли.
	 */
	useEffect(() => {
		const bodyElem = bodyRef?.current;
		let activeStepItem: null | StepType = null;

		// Пропустите прокрутку, если не ПЕРВЫЙ рендеринг и автопрокрутка отключена
		if (!initialRenderRef.current && !enableAutoScroll) {
			return;
		}

		// После первого рендеринга пометьте как не начальный
		if (initialRenderRef.current) {
			initialRenderRef.current = false;
		}

		const activeStepIndex = steps.findIndex(item => {
			const isActive = item.id === activeStepId;
			if (isActive) {
				activeStepItem = item;
			}

			return isActive;
		});

		if (bodyElem && activeStepItem) {
			scrollToStep(bodyElem.children[activeStepIndex], 'center');
			setCounter(activeStepIndex);
		}
	}, [activeStepId, steps, enableAutoScroll]);

	/**
	 * Скроллит до выбранного шага
	 */
	const scrollToStep = (stepElem: Element, inline?: ScrollLogicalPosition): void => {
		stepElem.scrollIntoView({
			block: 'nearest',
			behavior: 'smooth',
			inline: inline || 'start',
		});
	};

	/**
	 * Навигация вправо.
	 */
	const handleRightClick = (): void => {
		const bodyObj = bodyRef?.current;

		if (!bodyObj || bodyObj.scrollLeft + bodyObj.clientWidth >= bodyObj.scrollWidth) {
			return;
		}

		let newValue = counter + switchLength;

		if (newValue > bodyObj.children.length - 1) {
			newValue = bodyObj.children.length - 1;
		}

		scrollToStep(bodyObj.children[newValue]);
		setCounter(newValue);
	};

	/**
	 * Навигация влево.
	 */
	const handleLeftClick = (): void => {
		const bodyObj = bodyRef?.current;

		if (!bodyObj) {
			return;
		}

		let newValue = counter - switchLength;

		if (newValue < 0) {
			newValue = 0;
		}

		scrollToStep(bodyObj.children[newValue]);
		setCounter(newValue);
	};

	return (
		<div
			data-testid="Stepper"
			className={classNames(
				'dsb_stepper',
				mobile && 'dsb_stepper__mobile',
				direction === 'vertical' && 'dsb_stepper__vertical',
				className,
			)}
			{...props}
		>
			<div
				ref={bodyRef}
				className={classNames(
					'dsb_stepper-body',
					`dsb_stepper-body__${direction}`,
					mobile && 'dsb_stepper-body__mobile',
				)}
			>
				{!mobile &&
					steps?.map((step, i) => (
						<StepperStep
							{...step}
							direction={direction}
							activated={activeStepId === step.id}
							onClick={onStepChange}
							key={step.id}
							order={i + 1}
						/>
					))}
				{mobile &&
					steps?.map((step, i) => (
						<StepperMobileStep
							{...step}
							activated={activeStepId === step.id}
							onClick={onStepChange}
							key={step.id}
							order={i + 1}
						/>
					))}
			</div>
			{showLeftButton && (
				<Button
					onClick={handleLeftClick}
					size="large"
					variant="overlay"
					startIcon={<Icon iconName={Icons.ArrowLeft} />}
					className="dsb_stepper-button dsb_stepper-button__arrow-left"
				/>
			)}
			{showRightButton && (
				<Button
					onClick={handleRightClick}
					size="large"
					variant="overlay"
					startIcon={<Icon iconName={Icons.ArrowRight} />}
					className="dsb_stepper-button dsb_stepper-button__arrow-right"
				/>
			)}
		</div>
	);
};
